#!/usr/bin/env python3\n\"\"\"\nAdd captions to PlayStore screenshots\n\nUsage:\n  python3 add_captions_to_screenshots.py\n\nRequirements:\n  pip install Pillow\n\"\"\"\n\nimport os\nimport sys\nfrom pathlib import Path\n\ntry:\n    from PIL import Image, ImageDraw, ImageFont\nexcept ImportError:\n    print(\"Error: Pillow is not installed.\")\n    print(\"Install with: pip install Pillow\")\n    sys.exit(1)\n\n# Screenshot captions\nCAPTIONS = {\n    \"screenshot-1.png\": \"Solve word mysteries\",\n    \"screenshot-2.png\": \"Smart hints to guide you\",\n    \"screenshot-3.png\": \"Compete on global leaderboards\",\n    \"screenshot-4.png\": \"Customize your experience\",\n    \"screenshot-5.png\": \"Unlock achievements and rewards\",\n}\n\nSCREENSHOTS_DIR = \"screenshots/phone\"\nOUTPUT_DIR = \"screenshots/phone-captioned\"\n\ndef add_caption_to_image(image_path, caption, output_path, position=\"top\", font_size=50):\n    \"\"\"\n    Add text caption to image.\n    \n    Args:\n        image_path: Path to input image\n        caption: Text to add\n        output_path: Path to save output\n        position: \"top\" or \"bottom\"\n        font_size: Font size for caption\n    \"\"\"\n    try:\n        # Open image\n        img = Image.open(image_path)\n        \n        # Create drawing context\n        draw = ImageDraw.Draw(img)\n        \n        # Try to load a nice font, fallback to default\n        try:\n            # Try different font paths\n            font_paths = [\n                \"/usr/share/fonts/truetype/dejavu/DejaVuSans-Bold.ttf\",\n                \"/usr/share/fonts/truetype/liberation/LiberationSans-Bold.ttf\",\n                \"/System/Library/Fonts/Helvetica.ttc\",  # macOS\n                \"C:\\\\Windows\\\\Fonts\\\\Arial.ttf\",  # Windows\n            ]\n            \n            font = None\n            for font_path in font_paths:\n                if os.path.exists(font_path):\n                    font = ImageFont.truetype(font_path, font_size)\n                    break\n            \n            if font is None:\n                font = ImageFont.load_default()\n        except:\n            font = ImageFont.load_default()\n        \n        # Get image dimensions\n        width, height = img.size\n        \n        # Get text bounding box\n        bbox = draw.textbbox((0, 0), caption, font=font)\n        text_width = bbox[2] - bbox[0]\n        text_height = bbox[3] - bbox[1]\n        \n        # Calculate position\n        x = (width - text_width) // 2\n        \n        if position == \"top\":\n            y = 40\n        else:  # bottom\n            y = height - text_height - 40\n        \n        # Draw text with shadow for better readability\n        shadow_offset = 2\n        shadow_color = (0, 0, 0)\n        text_color = (255, 255, 255)\n        \n        # Draw shadow\n        for offset_x in range(-shadow_offset, shadow_offset + 1):\n            for offset_y in range(-shadow_offset, shadow_offset + 1):\n                if offset_x != 0 or offset_y != 0:\n                    draw.text((x + offset_x, y + offset_y), caption, font=font, fill=shadow_color)\n        \n        # Draw main text\n        draw.text((x, y), caption, font=font, fill=text_color)\n        \n        # Save output\n        img.save(output_path, quality=95)\n        return True\n    except Exception as e:\n        print(f\"Error processing {image_path}: {e}\")\n        return False\n\ndef main():\n    \"\"\"Add captions to all screenshots.\"\"\"\n    print(\"📝 Screenshot Caption Adder\")\n    print(\"=\" * 50)\n    \n    # Check if screenshots directory exists\n    if not os.path.exists(SCREENSHOTS_DIR):\n        print(f\"✗ Screenshots directory not found: {SCREENSHOTS_DIR}\")\n        print(f\"  Please capture screenshots first and place them in {SCREENSHOTS_DIR}\")\n        sys.exit(1)\n    \n    # Create output directory\n    os.makedirs(OUTPUT_DIR, exist_ok=True)\n    \n    # Process each screenshot\n    processed = 0\n    for filename, caption in CAPTIONS.items():\n        input_path = os.path.join(SCREENSHOTS_DIR, filename)\n        output_path = os.path.join(OUTPUT_DIR, filename)\n        \n        if os.path.exists(input_path):\n            if add_caption_to_image(input_path, caption, output_path):\n                print(f\"✓ {filename}: {caption}\")\n                processed += 1\n            else:\n                print(f\"✗ {filename}: Failed\")\n        else:\n            print(f\"⚠ {filename}: Not found in {SCREENSHOTS_DIR}\")\n    \n    print(\"\\n\" + \"=\" * 50)\n    if processed > 0:\n        print(f\"✅ Successfully processed {processed} screenshot(s)\")\n        print(f\"\\n📁 Output saved to: {OUTPUT_DIR}\")\n        print(\"\\n📤 Next steps:\")\n        print(\"  1. Review the captioned screenshots in the output folder\")\n        print(\"  2. Upload to Google Play Console\")\n        print(\"  3. Or replace originals: cp {OUTPUT_DIR}/*.png {SCREENSHOTS_DIR}/\")\n    else:\n        print(\"⚠️ No screenshots were processed\")\n        print(f\"\\nPlace your screenshots in {SCREENSHOTS_DIR} with names:\")\n        for filename in CAPTIONS.keys():\n            print(f\"  - {filename}\")\n\nif __name__ == \"__main__\":\n    main()\n